private takeNextPixels(): { chunk: ArrayBuffer; region?: Region } | null {
  const entry = this.pixelQueue[this.pixelReadIndex];
  this.pixelQueue[this.pixelReadIndex++] = undefined;
  if (entry === undefined) {
    this.compactQueue();
    return null;
  }
  this.queueDepth--;
  this.queuedBytes -= entry.chunk.byteLength;
  this.compactQueue();
  return entry;
}
